import sys

def main():
    n = int(sys.stdin.readline())
    board = [sys.stdin.readline().strip() for _ in range(n)]
    pieces = [
        (0, 0), (0, 1), (0, 2), (0, 3), (0, 4),
        (1, 0), (1, 1), (1, 2), (1, 3), (1, 4),
        (2, 0), (2, 1), (2, 2), (2, 3), (2, 4),
        (3, 0), (3, 1), (3, 2), (3, 3), (3, 4),
        (4, 0), (4, 1), (4, 2), (4, 3), (4, 4)
    ]
    for i in range(n):
        for j in range(n):
            if board[i][j] == '.':
                for p in pieces:
                    if i + p[0] < 0 or i + p[0] >= n or j + p[1] < 0 or j + p[1] >= n:
                        continue
                    if board[i + p[0]][j + p[1]] == '#':
                        break
                else:
                    return 'YES'
    return 'NO'

print(main())
